module top_module(
output reg [3:0] n_ascci,
input clk,
input add_ascci,
input reset_ascci
 );reg [3:0] count_reg;
always @(posedge clk) begin
		if (reset_ascci == 1)	count_reg <= 4'b0000;
		else if (add_ascci == 1) count_reg <= count_reg+1;
			else count_reg<=count_reg;
		end	
always @(count_reg) begin
		n_ascci <= count_reg;
	end
endmodule
